// ============================================================
// Calculate cost & check message limits
// ============================================================
const input = $input.first().json;

if (!input.customer_id || !input.tenant) {
  throw new Error('Missing customer_id or tenant');
}
if (!input.tenant.business_id) {
  throw new Error('Missing tenant.business_id');
}

// Model pricing (USD per 1M tokens)
const USD_TO_EGP = 49;
const pricing = {
  'anthropic/claude-haiku-4.5':  { input: 1.00,  output: 5.00 },
  'anthropic/claude-sonnet-4.5': { input: 3.00,  output: 15.00 },
  'anthropic/claude-opus-4.7':   { input: 15.00, output: 75.00 },
  'openai/gpt-4o':               { input: 2.50,  output: 10.00 },
  'openai/gpt-4o-mini':          { input: 0.15,  output: 0.60 },
  'openai/whisper-1':            { input: 0.006, output: 0.00 },
  'google/gemini-2.0-flash':     { input: 0.10,  output: 0.40 }
};

const model = input.model || 'anthropic/claude-sonnet-4.5';
const inputTokens  = parseInt(input.input_tokens  || 0);
const outputTokens = parseInt(input.output_tokens || 0);

const modelPricing = pricing[model] || pricing['anthropic/claude-sonnet-4.5'];
const costUsd = ((inputTokens * modelPricing.input) + (outputTokens * modelPricing.output)) / 1_000_000;
const costEgp = +(costUsd * USD_TO_EGP).toFixed(4);

// Plan-based message limits
const planLimits = {
  starter:    5000,
  business:   11000,
  enterprise: 20000
};

const tenantPlan = (input.tenant.plan_id || input.tenant.plan_tier || 'starter').toLowerCase();
const messagesLimit = planLimits[tenantPlan] || planLimits.starter;

return {
  json: {
    business_id:      input.tenant.business_id,
    tenant_order_id:  input.tenant.order_id || '',
    business_name:    input.tenant.business_name || '',
    customer_id:      input.customer_id,
    customer_name:    input.customer_name || '',
    customer_phone:   input.customer_phone || input.customer_id || '',
    plan_id:          tenantPlan,
    messages_limit:   messagesLimit,
    model:            model,
    input_tokens:     inputTokens,
    output_tokens:    outputTokens,
    cost_usd:         +costUsd.toFixed(6),
    cost_egp:         costEgp,
    operation_type:   input.operation_type || 'chat',
    timestamp:        new Date().toISOString()
  }
};

// ============================================================
// Check quota from Supabase usage_counters
// ============================================================
const quotaRows = $input.first().json;
const calc = $('CALCULATE_COST_LOGIC').first().json;

// quotaRows is an array from Supabase REST
const rows = Array.isArray(quotaRows) ? quotaRows : [];
const record = rows[0] || null;

if (record) {
  const currentMessages = parseInt(record.messages_sent || 0);
  const currentCost     = parseFloat(record.cost_egp_total || 0);
  const newMessageCount = currentMessages + 1;
  const newCost         = +(currentCost + calc.cost_egp).toFixed(4);
  const remaining       = calc.messages_limit - newMessageCount;
  const limitExceeded   = newMessageCount > calc.messages_limit;

  return {
    json: {
      ...calc,
      quota_record_id:  record.id,
      is_new_quota_record: false,
      messages_used:    newMessageCount,
      total_cost_egp:   newCost,
      messages_remaining: Math.max(0, remaining),
      limit_exceeded:   limitExceeded,
      action: limitExceeded ? 'fallback_model' : 'allow'
    }
  };
} else {
  // No record yet — first message from this business
  return {
    json: {
      ...calc,
      quota_record_id:  null,
      is_new_quota_record: true,
      messages_used:    1,
      total_cost_egp:   calc.cost_egp,
      messages_remaining: calc.messages_limit - 1,
      limit_exceeded:   false,
      action: 'allow'
    }
  };
}

const input = $input.first().json;
const calcData = $('CHECK_QUOTA_LOGIC').first().json;
return {
  json: {
    success: true,
    business_id:        calcData.business_id,
    customer_id:        calcData.customer_id,
    cost_usd:           calcData.cost_usd,
    cost_egp:           calcData.cost_egp,
    messages_used:      calcData.messages_used,
    messages_remaining: calcData.messages_remaining,
    limit_exceeded:     calcData.limit_exceeded,
    action:             calcData.action,
    model_used:         calcData.model,
    message: calcData.limit_exceeded
      ? `وصلت للحد الأقصى من الرسائل (${calcData.messages_limit}). سيتم تخفيض النموذج مؤقتاً.`
      : 'تم تحديث الكوتا بنجاح'
  }
};
